/** 複製原始檔案，並新增 CC 模組匯入 */
import { _decorator, Component, log, sp } from "cc";
import SpineKit from "db://astarte-framework/Component/Spine/SpineKit";
import GameView from "./GameView";
import { eventManager } from "db://astarte-framework/Managers";
import Game_Define from "./Game_Define";
import { Common } from "./Common/Common";
import { AudioManager } from "./Audio/AudioManager";

/** 動畫名稱：索引 0 = 橫版, 索引 1 = 直版 */
const AnimName = {
    Start: ["OPAnim", "OPAnim_Straight"],
};

const { ccclass, property } = _decorator;

@ccclass
export default class GameIntro extends Component
{
    @property( {
        type: sp.Skeleton,
        tooltip: "spine"
    } )
    private m_spines: sp.Skeleton[] = [];

    /**
     * @ch 遊戲視窗
     */
    private m_gameView: GameView = null;

    /**
     * @ch 最後一個 active 的索引
     */
    private m_lastActiveIndex: number = -1;

    /**
     * @ch 是否已經初始化
     */
    private m_isInitialized: boolean = false;

    /**
     * @ch 初始化
     * @param gameView 遊戲視窗
     */
    Init( gameView: GameView )
    {
        if (this.m_isInitialized) return;
        this.m_isInitialized = true;
        this.m_gameView = gameView;
        this.SetSpineActive( -1, false );
        this.RegisterEvent();
    }

    onDestroy()
    {
        if (!this.m_isInitialized) return;
        this.UnregisterEvent();
        this.m_isInitialized = false;
        this.m_gameView = null;
        this.m_lastActiveIndex = -1;
    }

    /**
     * @ch 註冊事件
     */
    private RegisterEvent()
    {
        eventManager.Register(Game_Define.EVENT.DEVICE_ROTATION, this);
    }

    /**
     * @ch 取消註冊事件
     */
    private UnregisterEvent()
    {
        eventManager.UnRegister(Game_Define.EVENT.DEVICE_ROTATION, this);
    }

    /**
     * @ch 事件
     * @param event 事件名稱
     * @param args 事件參數
     */
    OnEvent( event: string, ...args: any[] )
    {
        switch (event)
        {
            case Game_Define.EVENT.DEVICE_ROTATION:
                this.UpdateUI();
                break;
        }
    }

    /**
     * @ch 更新UI
     */
    UpdateUI()
    {
        if ( !this.m_gameView || this.m_spines.length === 0 ) return;
        const activeIndex = this.m_gameView.IsLandscape ? 0 : 1;
        if ( this.m_lastActiveIndex === activeIndex ) return;

        if ( this.m_lastActiveIndex >= 0 )
        {
            this.SetSpineActive( this.m_lastActiveIndex, false );
        }
        this.SetSpineActive( activeIndex, true );
        this.m_lastActiveIndex = activeIndex;
    }

    start()
    {
        for ( let i = 0; i < this.m_spines.length; i++ )
        {
            this.m_spines[ i ].paused = false;
            SpineKit.PlayAnimation( this.m_spines[ i ], AnimName.Start[ i ] ?? AnimName.Start[ 0 ] );
            this.m_spines[ i ].paused = true;
        }
    }

    /**
     * @ch 展示intro
     * @param index 索引 0:橫 1:直
     */
    async ShowIntro(index: number)
    {
        log("ShowIntro start");
        if (index < 0 || index >= this.m_spines.length)
            return;

        Common.SetLockOrientation(true);        
        this.SetSpineActive( index, true );
        const spine = this.m_spines[ index ];
        if (spine) {
            spine.node.active = true;
            spine.paused = false;
            AudioManager.Play(AudioManager.AudioClips.Intro_Bgm);
            await SpineKit.PlayAnimation(
                spine,
                AnimName.Start[ index ] ?? AnimName.Start[ 0 ],
                false,
                0,
                ( event: string ) =>
                {
                }
            );
            spine.node.active = false;
        }

        log("ShowIntro end");
        this.node.active = false;
        Common.SetLockOrientation(false);
    }

    /**
     * @ch 設置spine的active
     * @param index 索引 0:橫 1:直 負數:全部
     * @param isActive 
     */
    SetSpineActive( index: number, isActive: boolean )
    {
        if (index < 0) {
            this.m_spines.forEach(spine => spine.node.active = isActive);
            return;
        }
        if (index >= this.m_spines.length) {
            return;
        }
        this.m_spines[index].node.active = isActive;
    }
}

