import { _decorator, Component, sp } from 'cc';
import Game_Define from "../Game_Define";
import SpineKit from 'db://astarte-framework/Component/Spine/SpineKit';

const { ccclass, property } = _decorator;

/**@en Basic Symbol Spine @ch 基礎Spine */
@ccclass('BaseSpine')
export class BaseSpine extends Component
{
    /**@en The spine(which will be stored in node pool) @ch 將被放置於node pool的spine*/
    @property( {
        type: sp.Skeleton,
        displayName: "Spine 骨骼動畫組件"
    } )
    protected m_spine: sp.Skeleton = null;

    private _animNameCache: WeakMap<sp.SkeletonData, Set<string>> = new WeakMap();

    /**
     * @ch 取得 Spine 骨骼動畫組件
     * @returns {sp.Skeleton} Spine 骨骼動畫組件
     */
    public get Spine(): sp.Skeleton
    {
        return this.m_spine;
    }

    /**
     * @ch 停止所有軌道動畫並重置為 Setup Pose
     * @returns {void}
     */
    Stop()
    {
        if (!this.m_spine) return;
        this.m_spine.clearTracks();
        this.m_spine.setToSetupPose();
    }

    /**
     * @ch 暫停 Spine 動畫
     * @returns {void}
     */
    Pause()
    {
        if (!this.m_spine) return;
        this.m_spine.paused = true;
    }

    /**
     * @ch 恢復 Spine 動畫
     * @returns {void}
     */
    Resume()
    {
        if (!this.m_spine) return;
        this.m_spine.paused = false;
    }

    /**
     * @ch 設定 Spine 的皮膚
     * @param {string} skinName 皮膚名稱
     * @param {sp.Skeleton} [target=this.m_spine] 目標 Spine 組件
     * @returns {void}
     */
    SetSkin(skinName: string, target = this.m_spine)
    {
        if (!target) return;
        target.setSkin(skinName);
        target.setSlotsToSetupPose();
    }

    /**
     * @ch 設定當前節點的啟用狀態
     * @param {boolean} v 是否啟用
     * @returns {void}
     */
    SetNodeActivity(v: boolean)
    {
        this.node.active = v;
    }

    /**
     * @ch 設定 Spine 節點的啟用狀態
     * @param {boolean} v 是否啟用
     * @returns {void}
     */
    SetSpineNodeActivity( v: boolean )
    {
        if (!this.m_spine) return;
        this.m_spine.node.active = v;
    }

    /**
     * @ch 使用 Promise 控制播放 Spine 動畫
     * @param {string} animName 動畫名稱
     * @param {sp.Skeleton} [target=this.m_spine] 目標 Spine 組件
     * @param {boolean} [isLoop=false] 是否循環播放
     * @param {number} [timeScale=Game_Define.SpeedUp] 播放速度縮放
     * @param {(eventName: string) => void} [eventCb] 動畫事件回呼
     * @param {number} [trackIdx=0] 軌道索引
     * @returns {Promise<boolean>} 動畫成功開始播放回傳 true，否則回傳 false
     */
    PlayAnimation(
        animName: string,
        target = this.m_spine,
        isLoop: boolean = false,
        timeScale: number = Game_Define.SpeedUp,
        eventCb?: ( eventName: string ) => void,
        trackIdx: number = 0
    ) : Promise<boolean>
    {
        if (!target) {
            console.warn(`[BaseSpine] target spine is null, cannot play animation: ${animName}`);
            return Promise.resolve(false);
        }

        // 檢查 Spine 骨骼資料是否存在
        if (!target.skeletonData) {
            console.warn(`[BaseSpine] Spine skeleton data is null for animation: ${animName}`);
            return Promise.resolve(false);
        }

        // 使用快取檢查動畫是否存在，避免每次 O(n) 線性搜尋
        if (!this.HasAnimation(target.skeletonData, animName)) {
            console.warn(`[BaseSpine] Animation "${animName}" not found in spine: ${target.node.name}`);
            return Promise.resolve(false);
        }

        target.timeScale = timeScale;
        target.clearTrack(trackIdx);

        return SpineKit.PlayAnimation(
            target,
            animName,
            isLoop,
            trackIdx,
            eventCb
        );
    }

    /**
     * @ch 檢查 Spine 動畫是否存在
     * @param skeletonData Spine 骨骼資料
     * @param animName 動畫名稱
     * @returns {boolean} 動畫存在回傳 true，否則回傳 false
     */
    private HasAnimation(skeletonData: sp.SkeletonData, animName: string): boolean
    {
        if (!this._animNameCache.has(skeletonData)) {
            const runtimeData = skeletonData.getRuntimeData();
            if (!runtimeData) return false;
            this._animNameCache.set(skeletonData, new Set(runtimeData.animations.map((a: { name: string }) => a.name)));
        }
        return this._animNameCache.get(skeletonData)!.has(animName);
    }
}

