import { _decorator, Component, easing, error, EventKeyboard, Input, input, KeyCode, Label, log, Node, Tween, tween, Vec3 } from 'cc';
import { BaseSpine } from '../Spine/BaseSpine';
import { NumberAnimation } from '../Common/NumberAnimation';
import { eventManager, newBottombarManager } from 'db://astarte-framework/Managers';
import { Define, tools } from 'db://astarte-framework/utilis';
import { REEL_MANAGER_EVENT } from '../ReelManager';
import { Common, PopupNodeData } from '../Common/Common';
import { JP_EVENT } from '../JP/JP_Define';
import { AudioManager } from '../Audio/AudioManager';
import GameView from '../GameView';
import { DEBUG } from 'cc/env';
const { ccclass, property } = _decorator;

/**@ch 免費遊戲你贏了事件*/
export const FREE_GAME_YOU_WIN_EVENT = {
    /**
     * @ch 播放動畫（含進退場）
     * @param (必填) winValue 贏得金額
     * @param (必填) roundNumber 回合數字
     * @param (選填) callback 完成後回調
     */
    PLAY_ANIM: "FREE_GAME_YOU_WIN_PLAY_ANIM",
}

@ccclass('FreeGameYouWin')
export class FreeGameYouWin extends Component {
    //#region Constants
    /**
     * @ch 需要註冊的事件列表
     */
    private static readonly EVENTS_TO_REGISTER = [
        FREE_GAME_YOU_WIN_EVENT.PLAY_ANIM,
    ];

    /**@ch 你贏了動畫 橫版*/
    private static readonly ANIM_YOU_WON_BOARD = 'YouWonBoard';

    /**@ch 你贏了動畫 直版*/
    private static readonly ANIM_YOU_WON_BOARD_PORTAIT = 'YouWonBoard_Straight';

    private static readonly SPINE_EVENT_NUM_COUNT_START = 'NUMCount_Start';

    /**@ch 轉輪下移延遲（秒）*/
    private static readonly REEL_MOVE_DOWN_DELAY: number = 0;

    /**@ch 轉輪下移距離（Y 軸偏移量，負值為向下）*/
    private static readonly REEL_MOVE_DOWN_OFFSET_Y: number = -1000;

    /**@ch 轉輪下移動畫時長（秒）*/
    private static readonly REEL_MOVE_DOWN_DURATION: number = 1;

    /**@ch 轉輪恢復延遲（秒）*/
    private static readonly REEL_RESTORE_DELAY: number = 7.4;

    /**@ch 轉輪恢復動畫時長（秒）*/
    private static readonly REEL_RESTORE_DURATION: number = 0;
    //#endregion Constants

    //#region Properties
    /**@ch UI節點*/
    @property( {
        type: Node,
        tooltip: "UI節點"
    } )
    private m_uiNode: Node = null;

    @property( {
        type: BaseSpine,
        tooltip: "你贏了動畫"
    } )
    private m_youWinSpine: BaseSpine = null;

    @property( {
        type: NumberAnimation,
        tooltip: "贏得金額"
    } )
    private m_winValueLabel: NumberAnimation = null;

    @property( {
        type: Label,
        tooltip: "回合數字"
    } )
    private m_roundNumberLabel: Label = null;

    /**@ch 要掛載的根節點*/
    @property( {
        type: Node,
        tooltip: "要掛載的根節點"
    } )
    private m_pushRootNode: Node = null;
    //#endregion Properties

    //#region Variables
    /**@ch 是否已註冊事件 */
    private m_isEventRegistered: boolean = false;

    /**@ch 轉輪根節點（透過事件取得）*/
    private m_reelRootNode: Node = null;

    /**@ch 轉輪節點的堆疊資料（用於 PopNode 還原）*/
    private m_reelRootNodeData: PopupNodeData = null;    

    /**@ch 轉輪節點移動前的原始位置*/
    private m_reelOriginalPosition: Vec3 = new Vec3();

    /**@ch 遊戲視圖*/
    private m_gameView: GameView = null;
    //#endregion Variables

    //#region Methods
    /**
     * @ch 檢查節點是否有效
     * @param node 要檢查的節點
     * @param nodeName 節點名稱（用於錯誤訊息）
     * @returns 是否有效
     */
    private IsNodeValid<T>( node: T, nodeName: string ): node is NonNullable<T>
    {
        if (!node) {
            error(`[FreeGameYouWin] ${nodeName} is empty or null`);
            return false;
        }
        return true;
    }

    onLoad()
    {
        this.RegisterEvent();
        this.RegisterTestKeyCodes();
    }

    start()
    {
        this.SetupNumberAnimation();
        this.FetchReelRootNode();
    }

    onDestroy()
    {
        this.UnregisterEvent();
        this.UnregisterTestKeyCodes();
    }

    /**
     * @ch 設定數字動畫的格式化函數
     */
    private SetupNumberAnimation()
    {
        if (this.m_winValueLabel) {
            this.m_winValueLabel.SetFormatFunction((value: number) => {
                return tools.FormatNumberThousands(newBottombarManager.GetDisplayValue(value), tools.FORMAT_NUMBER_TYPE.DEFINE_DOT_NONE_ZERO);
            });
        }
    }

    /**
     * @ch 註冊事件
     */
    private RegisterEvent()
    {
        if (this.m_isEventRegistered) {
            return;
        }

        FreeGameYouWin.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.Register(eventName, this);
        });

        this.m_isEventRegistered = true;
    }

    /**
     * @ch 取消註冊事件
     */
    private UnregisterEvent()
    {
        if (!this.m_isEventRegistered) {
            return;
        }

        FreeGameYouWin.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.UnRegister(eventName, this);
        });

        this.m_isEventRegistered = false;
    }

    /**
     * @ch 事件處理器
     * @param event 事件名稱
     * @param args 參數
     */
    OnEvent( event: string, ...args: any[] )
    {
        switch ( event ) {
            case FREE_GAME_YOU_WIN_EVENT.PLAY_ANIM:
                if (!this.ValidatePlayAnimParam(args)) {
                    error('[FreeGameYouWin] PLAY_ANIM event requires parameters: (winValue: number, roundNumber: number, callback?: () => void)');
                    return;
                }
                this.PlayAnim( args[0], args[1], args[2] );
                break;
        }
    }

    /**
     * @ch 驗證 PLAY_ANIM 參數
     * @param args 參數陣列
     * @returns 是否為有效的參數
     */
    private ValidatePlayAnimParam( args: any[] ): args is [number, number, (() => void)?]
    {
        return args.length >= 2 &&
               typeof args[0] === 'number' &&
               typeof args[1] === 'number' &&
               (args.length === 2 || typeof args[2] === 'function' || args[2] === undefined || args[2] === null);
    }

    /**
     * @ch 設置UI節點顯示
     * @param isShow 是否顯示
     */
    private SetUIShow( isShow: boolean )
    {
        if (!this.IsNodeValid(this.m_uiNode, 'm_uiNode')) {
            return;
        }
        this.m_uiNode.active = isShow;
    }

    /**
     * @ch 是否為直版
     * @returns 是否為直版
     */
    private IsPortrait(): boolean
    {
        if (!this.m_gameView) {
            this.m_gameView = Common.GetGameView();
        }
        if (!this.m_gameView) {
            return false;
        }
        return !this.m_gameView.IsLandscape;
    }

    /**
     * @ch 播放動畫（含進退場）
     * @param winValue 贏得金額
     * @param roundNumber 回合數字
     * @param callback 完成後回調
     */
    private async PlayAnim( winValue: number, roundNumber: number, callback?: () => void ): Promise<void>
    {
        try {
            this.PushAndMoveReelDown();
            this.RestoreReelPosition();
            this.SetUIShow( true );
            this.SetRoundNumber( roundNumber );
            if (this.m_winValueLabel) {
                this.m_winValueLabel.Reset();
            }
            if (this.m_youWinSpine) {
                this.PlayYouWonBgmAudio();
                this.PlayOutAudio(5.8);
                await this.m_youWinSpine.PlayAnimation(
                    this.IsPortrait() ? FreeGameYouWin.ANIM_YOU_WON_BOARD_PORTAIT : FreeGameYouWin.ANIM_YOU_WON_BOARD,
                    this.m_youWinSpine.Spine,
                    false,
                    1,
                    (eventName: string) => {
                        if (eventName === FreeGameYouWin.SPINE_EVENT_NUM_COUNT_START) {
                            this.m_winValueLabel?.PlayRolling(0, winValue, 4);
                        }
                    }
                );
            }
            this.SetUIShow( false );
            callback?.();
        } catch (err) {
            error('[FreeGameYouWin] PlayAnim error:', err);
            this.ForceRestoreReelPosition();
            callback?.();
        }
    }

    /**
     * @ch 設置回合數字
     * @param roundNumber 回合數字
     */
    private SetRoundNumber( roundNumber: number )
    {
        if (this.m_roundNumberLabel) {
            this.m_roundNumberLabel.string = roundNumber.toString();
        }
    }

    /**
     * @ch 播放你贏了背景音樂
     */
    private PlayYouWonBgmAudio(): void
    {
        AudioManager.Play(AudioManager.AudioClips.FG_YouWonBgm);
    }

    /**
     * @ch 播放退場音效
     * @param delay 延遲多久才播放（秒）
     * @returns 
     */
    private async PlayOutAudio(delay: number = FreeGameYouWin.REEL_MOVE_DOWN_DELAY): Promise<void>
    {
        await Define.Wait(this, delay);
        AudioManager.Play(AudioManager.AudioClips.FG_Out);
    }
    //#endregion Methods

    //#region Reel Root Node Management
    /**
     * @ch 透過事件取得轉輪根節點
     */
    private FetchReelRootNode(): void
    {
        eventManager.Dispatch(REEL_MANAGER_EVENT.GET_ROOT_NODE, (node: Node) => {
            this.m_reelRootNode = node;
        });
    }

    /**
     * @ch 將轉輪根節點推入 m_pushRootNode 並開始往下移動
     * @param delay 延遲多久才開始移動（秒）
     * @param offsetY Y 軸偏移量（負值為向下）
     * @param duration 移動動畫時長（秒）
     */
    private PushAndMoveReelDown(
        delay: number = FreeGameYouWin.REEL_MOVE_DOWN_DELAY,
        offsetY: number = FreeGameYouWin.REEL_MOVE_DOWN_OFFSET_Y,
        duration: number = FreeGameYouWin.REEL_MOVE_DOWN_DURATION,
    ): void
    {
        if (!this.m_reelRootNode || !this.m_pushRootNode) {
            return;
        }

        eventManager.Dispatch(JP_EVENT.HIDE_UI);

        this.m_reelRootNodeData = Common.PushNode(this.m_reelRootNode, this.m_pushRootNode);
        this.m_reelOriginalPosition.set(this.m_reelRootNode.position);

        const targetPosition = this.m_reelRootNode.position.clone();
        targetPosition.y += offsetY;

        tween(this.m_reelRootNode)
            .delay(delay)
            .to(duration, { position: targetPosition }, { easing: easing.cubicOut })
            .start();
    }

    /**
     * @ch 延遲後以動畫恢復轉輪根節點到原位置，動畫結束後放回原父節點
     * @param delay 延遲多久才開始恢復（秒）
     * @param duration 恢復動畫時長（秒）
     */
    private RestoreReelPosition(
        delay: number = FreeGameYouWin.REEL_RESTORE_DELAY,
        duration: number = FreeGameYouWin.REEL_RESTORE_DURATION,
    ): void
    {
        if (!this.m_reelRootNode || !this.m_reelRootNodeData) {
            return;
        }

        const nodeData = this.m_reelRootNodeData;
        this.m_reelRootNodeData = null;

        tween(this.m_reelRootNode)
            .delay(delay)
            .to(duration, { position: this.m_reelOriginalPosition.clone() }, { easing: easing.cubicOut })
            .call(() => {
                Common.PopNode(nodeData);
                eventManager.Dispatch(JP_EVENT.SHOW_UI);
            })
            .start();
    }

    /**
     * @ch 強制立即恢復轉輪根節點（用於異常路徑，跳過動畫直接還原）
     */
    private ForceRestoreReelPosition(): void
    {
        if (!this.m_reelRootNode) {
            return;
        }

        Tween.stopAllByTarget(this.m_reelRootNode);
        this.m_reelRootNode.setPosition(this.m_reelOriginalPosition);

        if (this.m_reelRootNodeData) {
            Common.PopNode(this.m_reelRootNodeData);
